import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';

interface Task {
  id: number;
  title: string;
  description: string;
  status: string;
  priority: string;
  dueDate: string;
  assignee: string;
  createdDate: string;
}

export default function TaskDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [task, setTask] = useState<Task | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockTask: Task = {
      id: Number(id),
      title: 'Design UI Components',
      description: 'Design and implement new UI components for the dashboard',
      status: 'in-progress',
      priority: 'high',
      dueDate: '2026-06-15',
      assignee: 'John Doe',
      createdDate: '2026-06-01',
    };
    
    setTask(mockTask);
    setLoading(false);
  }, [id]);

  if (loading) return <div className="p-6">Loading...</div>;
  if (!task) return <div className="p-6">Task not found</div>;

  return (
    <div className="p-6 max-w-2xl mx-auto space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">{task.title}</h1>
        <Button variant="outline" onClick={() => navigate('/tasks')}>Back</Button>
      </div>

      <div className="grid gap-6 md:grid-cols-2">
        <div className="p-4 border rounded-lg">
          <h3 className="font-semibold mb-4">Task Details</h3>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Description</p>
              <p>{task.description}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Status</p>
              <p className="font-medium capitalize">{task.status}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Priority</p>
              <p className={`font-medium capitalize ${task.priority === 'high' ? 'text-red-600' : task.priority === 'medium' ? 'text-yellow-600' : 'text-green-600'}`}>
                {task.priority}
              </p>
            </div>
          </div>
        </div>

        <div className="p-4 border rounded-lg">
          <h3 className="font-semibold mb-4">Assignment</h3>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Assigned To</p>
              <p className="font-medium">{task.assignee}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Created Date</p>
              <p className="font-medium">{new Date(task.createdDate).toLocaleDateString()}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Due Date</p>
              <p className="font-medium">{new Date(task.dueDate).toLocaleDateString()}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="flex gap-2">
        <Button>Edit</Button>
        <Button variant="destructive">Delete</Button>
      </div>
    </div>
  );
}
